import React from 'react';
import styled from 'styled-components';
import { Link } from 'react-router-dom';
import { useTheme } from '../context/ThemeContext';

const HeroSection = styled.section`
  position: relative;
  display: flex;
  justify-content: center;
  align-items: center;
  padding: 0;
  color: white;
  width: 100%;
  min-height: 90vh;
  box-sizing: border-box;
  overflow: hidden;
  background: #5a0000;
  background-image: linear-gradient(rgba(90, 0, 0, 0.85), rgba(90, 0, 0, 0.85)), url('../assets/background.jpg');
  background-size: cover;
  background-position: center;
`;

const HeroBg = styled.div`
  position: absolute;
  top: 0; left: 0; right: 0; bottom: 0;
  z-index: 1;

  &::before {
    content: "";
    position: absolute;
    top: 0; left: 0; right: 0; bottom: 0;
    background-color: rgba(90, 0, 0, 0.4);
    opacity: 0.5;
    z-index: -1;
    transition: opacity 0.3s ease;
  }
`;

const HeroContent = styled.div`
  position: relative;
  z-index: 2;
  padding: 10% 0;
  width: 100%;
  height: 100%;
  text-align: center;
  animation: zoomOut 1s ease-in backwards;
`;

const Title = styled.h1`
  font-size: 5.5rem;
  margin-bottom: 0;
  line-height: 1.2;
  color: white;
  font-weight: bold;
  text-transform: uppercase;

  @media (max-width: 768px) {
    font-size: 2.5rem;
  }
`;

const Highlight = styled.span`
  font-size: 4.5rem;
  margin-bottom: 20px;
  line-height: 1.2;
  font-weight: 1000;
  color: #ff3a3a;
  text-transform: uppercase;
  position: relative;
  display: block;

  @media (max-width: 768px) {
    font-size: 3rem;
  }
`;

const Description = styled.p`
  font-size: 1.3rem;
  margin: 30px auto;
  max-width: 600px;
  line-height: 1.6;
  color: rgba(255, 255, 255, 0.8);
`;
  
const ButtonContainer = styled.div`
  display: flex;
  text-align: center;
  justify-content: center;
  gap: 20px;
  margin-top: 40px;
`;
  
const StyledButton = styled(Link)`
  text-decoration: none;
  color: rgba(255, 255, 255, 0.9);
  background: transparent;
  padding: 12px 30px;
  border-radius: 30px;
  font-size: 16px;
  font-weight: bold;
  transition: all 0.3s ease;
  position: relative;
  overflow: hidden;
  z-index: 1;
  border: 2px solid white;
  text-transform: uppercase;

  &:hover {
    transform: translateY(-3px);
    background: white;
    color: #5a0000;
  }
`;

const Hero = () => {
  const { theme, isDarkTheme } = useTheme();

  return (
    <HeroSection theme={theme}>
      <HeroBg isDarkTheme={isDarkTheme}>
        <HeroContent 
          data-aos="fade-right" 
          data-aos-duration="1000"
        >
          <Title>More Than</Title>
          <Highlight>An Agency</Highlight>
          <Description>
            Our agency is a dynamic fusion of innovation and expertise, committed to
            crafting visual experiences that leave an indelible mark.
          </Description>
          <ButtonContainer>
            <StyledButton 
              to="#"
              data-aos="zoom-in" 
              data-aos-delay="300"
            >
              2024 Best Agency
            </StyledButton>
            <StyledButton 
              to="#"
              data-aos="zoom-in" 
              data-aos-delay="400"
            >
              World Class Agency
            </StyledButton>
          </ButtonContainer>
        </HeroContent>
      </HeroBg>
    </HeroSection>
  );
};

export default Hero;
